import{_ as e}from"./chunks/微笑狼的公开仓库.gGdYP2E_.js";import{_ as i,o as t,c as l,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"Otomatik Etiketleme","description":"","frontmatter":{},"headers":[],"relativePath":"tr-TR/Other/auto-tagging.md","filePath":"tr-TR/Other/auto-tagging.md","lastUpdated":1781962217000}'),n={name:"tr-TR/Other/auto-tagging.md"};function d(s,a,o,g,p,c){return t(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="otomatik-etiketleme" tabindex="-1">Otomatik Etiketleme <a class="header-anchor" href="#otomatik-etiketleme" aria-label="Permalink to &quot;Otomatik Etiketleme&quot;">​</a></h1><p>Auto tagging şu bölümden yapılandırılır:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Auto Tagging</span></span></code></pre></div><p>Bu özellik görsel etiketlerini otomatik üretir. Etiketler arama, random image filtreleme, public gallery filtreleme ve yaş derecelendirmesine göre erişim kontrolü için kullanışlıdır.</p><h2 id="auto-tagging-neler-yapabilir" tabindex="-1">Auto Tagging Neler Yapabilir? <a class="header-anchor" href="#auto-tagging-neler-yapabilir" aria-label="Permalink to &quot;Auto Tagging Neler Yapabilir?&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Özellik</th><th>Açıklama</th></tr></thead><tbody><tr><td>Content tags üretme</td><td>Kişiler, sahneler, nesneler, sanat stili ve benzeri görsel içerik için etiket ekler.</td></tr><tr><td>Character tags üretme</td><td>Anime görselleri ve illüstrasyonlar için kullanışlıdır.</td></tr><tr><td>Orientation tags ekleme</td><td><code>landscape</code>, <code>portrait</code> veya <code>square</code> ekler.</td></tr><tr><td>Image rating ekleme</td><td>General, sensitive, questionable veya explicit içerik için <code>G/S/Q/E</code> derecelendirme sonuçlarını kaydeder.</td></tr><tr><td>Auto-tag on upload</td><td>Yeni yüklenen görseller otomatik olarak etiketleme akışına girer.</td></tr><tr><td>Batch tagging</td><td>Tüm klasörlerdeki veya seçili klasörlerdeki eski görsellere etiket ekler.</td></tr></tbody></table><h2 id="once-gerekenler" tabindex="-1">Önce Gerekenler <a class="header-anchor" href="#once-gerekenler" aria-label="Permalink to &quot;Önce Gerekenler&quot;">​</a></h2><p>En az bir erişilebilir Hugging Face Space URL hazırlayın.</p><p>Önerilen yöntem, SmilingWolf&#39;un <code>wd-tagger</code> Space&#39;ini kendi Hugging Face hesabınıza kopyalamaktır:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><p>Geçici test için public Space kullanabilirsiniz; ancak public Spaces birçok kullanıcı tarafından paylaşılır, kuyruğa girebilir, yavaşlayabilir veya geçici olarak kullanılamaz hale gelebilir. Kendi hesabınızdaki kopya, uzun vadeli auto tagging için daha kararlıdır.</p><h2 id="smilingwolf-space-ini-kopyalama" tabindex="-1">SmilingWolf Space&#39;ini Kopyalama <a class="header-anchor" href="#smilingwolf-space-ini-kopyalama" aria-label="Permalink to &quot;SmilingWolf Space&#39;ini Kopyalama&quot;">​</a></h2><ol><li>Hugging Face&#39;e giriş yapın.</li><li><code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code> adresini açın.</li></ol><p><img src="'+e+`" alt="SmilingWolf public Space" loading="lazy"></p><ol start="3"><li>Sağ üst köşedeki üç nokta menüsüne tıklayın.</li><li><code>Duplicate this Space</code> seçin.</li><li>Varsayılan Space adını koruyun veya <code>wd-tagger</code> gibi kendi adınızı seçin.</li><li>Visibility değerini <code>Public</code> yapın. Public Spaces ImgBed tarafından daha kolay çağrılır.</li><li>Başlangıçta varsayılan ücretsiz hardware ile devam edin. Kuyruk belirginleşirse daha sonra yükseltin.</li><li>Space&#39;i oluşturun ve build tamamlanana kadar bekleyin.</li></ol><p>Build tamamlandıktan sonra Space sayfanızı açın. URL genellikle şu şekildedir:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/your-name/wd-tagger</span></span></code></pre></div><p>Tarayıcı URL&#39;sini kopyalayıp ImgBed&#39;deki <code>Space URLs</code> alanına yapıştırın.</p><h2 id="birden-fazla-space-url-girme" tabindex="-1">Birden Fazla Space URL Girme <a class="header-anchor" href="#birden-fazla-space-url-girme" aria-label="Permalink to &quot;Birden Fazla Space URL Girme&quot;">​</a></h2><p>Her satıra bir Space URL girin.</p><table tabindex="0"><thead><tr><th>Değer</th><th>Açıklama</th></tr></thead><tbody><tr><td><code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code></td><td>SmilingWolf public Space. Geçici test için iyidir.</td></tr><tr><td><code>https://huggingface.co/spaces/lintonxue00/wd-tagger</code></td><td>Kopyalanmış Space sayfa URL&#39;si.</td></tr><tr><td><code>https://huggingface.co/spaces/your-name/wd-tagger</code></td><td>Kendi kopyaladığınız Space sayfa URL&#39;si.</td></tr></tbody></table><p>Birden fazla URL girebilirsiniz. ImgBed birden fazla Space&#39;i birlikte kullanır; bu da hızı artırabilir.</p><p>Bir Space geçici olarak kullanılamazsa diğerleri işlemeye devam edebilir.</p><h2 id="ayarlar" tabindex="-1">Ayarlar <a class="header-anchor" href="#ayarlar" aria-label="Permalink to &quot;Ayarlar&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Seçenek</th><th>Öneri</th></tr></thead><tbody><tr><td><code>Space URLs</code></td><td>Hazırladığınız Space URL&#39;lerini girin. En az bir tane kullanın.</td></tr><tr><td>Target folder</td><td>Tüm klasörler için boş bırakın. Yalnızca belirli bir dizini işlemek istiyorsanız klasör seçin.</td></tr><tr><td>Recognition model</td><td>Varsayılan olarak <code>wd-swinv2-tagger-v3</code> bırakın.</td></tr><tr><td>General tag threshold</td><td>Varsayılan değer çoğu görsel için uygundur. Düşük değer daha çok etiket, yüksek değer daha az etiket üretir.</td></tr><tr><td>Character tag threshold</td><td>Varsayılan değer temkinlidir ve hatalı character tags riskini azaltır.</td></tr><tr><td><code>MCut</code> automatic threshold</td><td>Başlangıçta kapalı bırakın. Etiket sayısına model karar versin istiyorsanız açın.</td></tr><tr><td>Auto-tag on upload</td><td>Yeni yüklenen görseller otomatik etiketlenecekse açın.</td></tr><tr><td>Start tagging</td><td>Eski görseller için elle batch tagging başlatır.</td></tr></tbody></table><h2 id="onerilen-baslangıc-degerleri" tabindex="-1">Önerilen Başlangıç Değerleri <a class="header-anchor" href="#onerilen-baslangıc-degerleri" aria-label="Permalink to &quot;Önerilen Başlangıç Değerleri&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Seçenek</th><th>Önerilen Değer</th></tr></thead><tbody><tr><td>Recognition model</td><td><code>wd-swinv2-tagger-v3</code></td></tr><tr><td>General tag threshold</td><td><code>0.35</code></td></tr><tr><td>Character tag threshold</td><td><code>0.85</code></td></tr><tr><td><code>MCut</code></td><td>Başlangıçta kapalı</td></tr><tr><td>Auto-tag on upload</td><td>Gerekirse etkin</td></tr></tbody></table><p>Etiket sayısı fazla gelirse general threshold değerini biraz yükseltin.</p><p>Etiket sayısı az gelirse general threshold değerini biraz düşürün.</p><h2 id="batch-tagging" tabindex="-1">Batch Tagging <a class="header-anchor" href="#batch-tagging" aria-label="Permalink to &quot;Batch Tagging&quot;">​</a></h2><ol><li><code>Space URLs</code> alanını doldurun.</li><li>Target folder seçin.</li><li>Start tagging düğmesine tıklayın.</li><li>İlerleme tamamlanana kadar bekleyin.</li></ol><p>Target folder boşsa ImgBed tüm klasörleri işler.</p><p>Batch tagging eski görseller için uygundur. Yeni görseller için auto-tag on upload etkinleştirin; böylece her seferinde elle çalıştırmanız gerekmez.</p><h2 id="auto-tag-on-upload" tabindex="-1">Auto-Tag on Upload <a class="header-anchor" href="#auto-tag-on-upload" aria-label="Permalink to &quot;Auto-Tag on Upload&quot;">​</a></h2><p>Auto-tag on upload etkinleştirildikten sonra yeni yüklenen görseller yapılandırılmış <code>Space URLs</code> adreslerini otomatik çağırır.</p><p>Uzun vadeli kullanım için uygundur.</p><p>Space kuyruğa girerse yükleme işlemi önce tamamlanabilir; etiketleme daha sonra devam eder.</p><h2 id="hangi-gorseller-islenir" tabindex="-1">Hangi Görseller İşlenir? <a class="header-anchor" href="#hangi-gorseller-islenir" aria-label="Permalink to &quot;Hangi Görseller İşlenir?&quot;">​</a></h2><p>Auto tagging ağırlıklı olarak görsel dosyalarını işler.</p><p>Zaten tam tags, orientation, rating, width ve height bilgilerine sahip görseller gereksiz Space çağrısını önlemek için atlanır.</p><p>ImgBed mümkün olduğunda yalnızca eksik bilgiyi tamamlar. Örneğin yalnızca orientation eksikse tam content tag flow çağırmadan orientation eklemeye çalışır.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="neden-kendi-space-imi-kopyalamalıyım" tabindex="-1">Neden Kendi Space&#39;imi Kopyalamalıyım? <a class="header-anchor" href="#neden-kendi-space-imi-kopyalamalıyım" aria-label="Permalink to &quot;Neden Kendi Space&#39;imi Kopyalamalıyım?&quot;">​</a></h3><p>Public Spaces birçok kullanıcı tarafından paylaşılır. Kendi kopyaladığınız Space çoğunlukla ImgBed siteniz tarafından kullanılır, bu yüzden genellikle daha hızlı ve güvenilirdir.</p><h3 id="space-surekli-baslıyor" tabindex="-1">Space Sürekli Başlıyor <a class="header-anchor" href="#space-surekli-baslıyor" aria-label="Permalink to &quot;Space Sürekli Başlıyor&quot;">​</a></h3><p>İlk oluşturma sonrasında veya uzun süre boşta kaldıktan sonra Space&#39;in başlaması zaman alabilir.</p><p>Önce Space sayfanızı açın. Bir görseli normal şekilde tanıyabildiğinde ImgBed&#39;e dönüp etiketlemeyi başlatın.</p><h3 id="space-url-nasıl-kopyalanır" tabindex="-1">Space URL Nasıl Kopyalanır? <a class="header-anchor" href="#space-url-nasıl-kopyalanır" aria-label="Permalink to &quot;Space URL Nasıl Kopyalanır?&quot;">​</a></h3><p>Hugging Face Space sayfanızı açın ve tarayıcı adresini kopyalayın.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/lintonxue00/wd-tagger</span></span>
<span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><h3 id="birden-fazla-space-ekleyebilir-miyim" tabindex="-1">Birden Fazla Space Ekleyebilir miyim? <a class="header-anchor" href="#birden-fazla-space-ekleyebilir-miyim" aria-label="Permalink to &quot;Birden Fazla Space Ekleyebilir miyim?&quot;">​</a></h3><p>Evet. Her satıra bir Space URL girin.</p><p>Birden fazla Space görselleri birlikte işler ve çok sayıda görseliniz varsa kullanışlıdır.</p><h3 id="etiketler-neden-ingilizce" tabindex="-1">Etiketler Neden İngilizce? <a class="header-anchor" href="#etiketler-neden-ingilizce" aria-label="Permalink to &quot;Etiketler Neden İngilizce?&quot;">​</a></h3><p>SmilingWolf modelleri İngilizce etiket üretir. Bu beklenen davranıştır.</p><p>Etiketler ağırlıklı olarak arama, filtreleme, random image API ve public gallery filtreleri için kullanılır.</p><h3 id="rating-tags-ne-icin-kullanılır" tabindex="-1">Rating Tags Ne İçin Kullanılır? <a class="header-anchor" href="#rating-tags-ne-icin-kullanılır" aria-label="Permalink to &quot;Rating Tags Ne İçin Kullanılır?&quot;">​</a></h3><p>Rating sonuçları Security Settings içindeki access mode ile birlikte çalışır.</p><p>Örneğin ziyaretçi erişimi yaş derecelendirmesiyle sınırlıysa public browsing ve random image özellikleri görselleri bu kurallara göre filtreler.</p><h2 id="kısa-akıs" tabindex="-1">Kısa Akış <a class="header-anchor" href="#kısa-akıs" aria-label="Permalink to &quot;Kısa Akış&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hugging Face&#39;e giriş yap</span></span>
<span class="line"><span>-&gt; SmilingWolf/wd-tagger aç</span></span>
<span class="line"><span>-&gt; Duplicate this Space</span></span>
<span class="line"><span>-&gt; Space build tamamlanana kadar bekle</span></span>
<span class="line"><span>-&gt; Space URL&#39;ni kopyala</span></span>
<span class="line"><span>-&gt; ImgBed&#39;de Space URLs alanını doldur</span></span>
<span class="line"><span>-&gt; Model ve thresholds seç</span></span>
<span class="line"><span>-&gt; Tagging başlat veya auto-tag on upload etkinleştir</span></span></code></pre></div>`,61)])])}const m=i(n,[["render",d]]);export{u as __pageData,m as default};
